+    fn test_linear_attention() {
+        let attention = LinearAttention::new(64, 32);
+
+        let query = vec![0.5; 64];
+        let keys: Vec<Vec<f32>> = (0..100).map(|_| vec![0.3; 64]).collect();
+        let values: Vec<Vec<f32>> = (0..100).map(|_| vec![1.0; 64]).collect();
