+#[test]
+fn test_exp_log_map_inverse() {
+    let p = vec![0.3, 0.2, 0.1];
+    let v = vec![0.1, -0.1, 0.05];
+    let c = 1.0;
+
+    // exp_p(log_p(q)) = q
+    let q = exp_map(&v, &p, c);
+    let v_recovered = log_map(&q, &p, c);
+
+    for (vi, &vr) in v.iter().zip(&v_recovered) {
+        assert!(
+            (vi - vr).abs() < 1e-4,
+            "exp and log should be inverses: {} vs {}",
+            vi, vr
+        );
+    }
+}
